#!/usr/bin/env python3
"""
setup_server1_vm.py
Run this ON dc-server1 to create all necessary project files.
Usage:  python3 setup_server1_vm.py
"""
import os, base64

files = {}
files['server/file_server.py'] = ''
files['config.json'] = ''

BASE = os.path.expanduser("~/distributed-chatroom")
for rel, b64 in files.items():
    path = os.path.join(BASE, rel)
    os.makedirs(os.path.dirname(path), exist_ok=True)
    with open(path, "wb") as f:
        f.write(base64.b64decode(b64))
    print("  created:", path)
os.makedirs(os.path.join(BASE, "logs"), exist_ok=True)
os.makedirs(os.path.join(BASE, "server"), exist_ok=True)
# create __init__.py
open(os.path.join(BASE, "server/__init__.py"), "a").close()
print()
print("dc-server1 setup complete! Files are in ~/distributed-chatroom/")
